#include <windows.h>

// DLL callback — lParam carries a pointer to the owning dialog
BOOL CALLBACK DeviceEnumProc(LPARAM lParam, LPARAM lParamContext)
{
    // No null-check, no magic validation — type-unsafe pointer recovery
    CISPDockingDlg* pDlg = reinterpret_cast<CISPDockingDlg*>(lParamContext);
    pDlg->OnDeviceFound(lParam);  // crash if lParamContext is wrong type
    return TRUE;
}
